import{_ as t,o,c as i,ag as s}from"./chunks/framework.DUvHsH_U.js";const h=JSON.parse('{"title":"Home Screen Top Sold Items and Brands Setup","description":"","frontmatter":{},"headers":[],"relativePath":"products-pricing/home-screen-top-sold-items-and-brands-setup.md","filePath":"products-pricing/home-screen-top-sold-items-and-brands-setup.md","lastUpdated":1777975835000}'),r={name:"products-pricing/home-screen-top-sold-items-and-brands-setup.md"};function a(n,e,l,c,g,p){return o(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="home-screen-top-sold-items-and-brands-setup" tabindex="-1">Home Screen Top Sold Items and Brands Setup <a class="header-anchor" href="#home-screen-top-sold-items-and-brands-setup" aria-label="Permalink to &quot;Home Screen Top Sold Items and Brands Setup&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This setup controls the dynamic <strong>Most Sold Items</strong> and <strong>Brands</strong> sections on the mobile app home screen. After setup, support teams can choose which product category feeds the Most Sold carousel and which parent category feeds the Brands carousel.</p><h2 id="erpnext-setup-steps" tabindex="-1">ERPNext Setup Steps <a class="header-anchor" href="#erpnext-setup-steps" aria-label="Permalink to &quot;ERPNext Setup Steps&quot;">​</a></h2><ol><li><p><strong>Log in as an Administrator</strong></p><ul><li>Open the ERPNext admin dashboard.</li><li>Log in with a System Manager or Administrator account.</li></ul></li><li><p><strong>Use the Mobile E-Commerce Control Panel if it is available</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <strong>Mobile E-Commerce Control Panel</strong> and open it.</li><li>If this page is available on the client&#39;s site, you can use it to manage these home screen sections faster.</li><li>From this page, create the Most Sold Items category.</li><li>Create the Brands parent category.</li><li>Create the brand subcategories under the Brands parent category.</li><li>Publish the categories and subcategories that should appear in the mobile app.</li><li>Assign or publish the Most Sold products under the correct Most Sold Items category.</li><li>Save your changes before testing in the mobile app.</li><li>If this page is not available, continue with the manual category and item steps below.</li></ul></li><li><p><strong>Create the Most Sold Items category</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <strong>Item Category List</strong> and open it.</li><li>Click <strong>New</strong>.</li><li>Enter a clear category name for the Most Sold section, such as <strong>Mobile Most Sold Items</strong>.</li><li>If this category should sit under an existing product category, select that category in <strong>Parent Item Category</strong>.</li><li>Confirm the category is active.</li><li>Check <strong>Show in Mobile Application</strong>.</li><li>Click <strong>Save</strong>.</li><li>Copy or write down the exact category name exactly as it appears in ERPNext.</li></ul></li><li><p><strong>Create the Brands parent category</strong></p><ul><li>Go back to <strong>Item Category List</strong>.</li><li>Click <strong>New</strong>.</li><li>Enter a clear parent category name for brands, such as <strong>Mobile Brands</strong>.</li><li>Leave <strong>Parent Item Category</strong> empty unless the client specifically wants this Brands category under another parent category.</li><li>Confirm the category is active.</li><li>Check <strong>Show in Mobile Application</strong>.</li><li>Click <strong>Save</strong>.</li><li>Copy or write down the exact category name exactly as it appears in ERPNext.</li></ul></li><li><p><strong>Connect the categories in Mobile E-Commerce Settings</strong></p><ul><li>Use the ERPNext search bar.</li><li>Search for <strong>Mobile E-Commerce Settings</strong> and open it.</li><li>Locate the <strong>Main settings</strong> section.</li><li>In <strong>Most sold items category</strong>, enter the exact name of the Most Sold Items category created earlier.</li><li>In <strong>Brand&#39;s parent category</strong>, enter the exact name of the Brands parent category created earlier.</li><li>Check both names carefully for spelling, capitalization, and extra spaces.</li><li>Click <strong>Save</strong>.</li></ul></li><li><p><strong>Add products to the Most Sold Items section</strong></p><ul><li>Go to <strong>Item List</strong>.</li><li>Open an item that should appear in the <strong>Most Sold Items</strong> carousel.</li><li>Confirm the item is <strong>Enabled</strong>.</li><li>Assign the item to the Most Sold Items category created earlier.</li><li>Open the <strong>Actions</strong> drop-down.</li><li>Click <strong>Publish in Website</strong>.</li><li>Confirm the item has the normal mobile catalog setup required for visible products, including image, selling UOM, pricing, and available stock where applicable.</li><li>Click <strong>Save</strong> if ERPNext asks you to save changes.</li><li>Repeat these steps for every item that should appear in the Most Sold carousel.</li></ul></li><li><p><strong>Add brand subcategories to the Brands section</strong></p><ul><li>Go to <strong>Item Category List</strong>.</li><li>Click <strong>New</strong>.</li><li>Enter the brand name as the category name, such as <strong>Brand A</strong>.</li><li>In <strong>Parent Item Category</strong>, select the Brands parent category created earlier.</li><li>Confirm the category is active.</li><li>Check <strong>Show in Mobile Application</strong>.</li><li>Add or confirm the brand image if the client wants a logo or visual tile to appear in the app.</li><li>Click <strong>Save</strong>.</li><li>Repeat these steps for every brand that should appear in the Brands carousel.</li></ul></li><li><p><strong>Test in the mobile app</strong></p><ul><li>Fully close and reopen the mobile app.</li><li>Open the home screen.</li><li>The <strong>Most Sold Items</strong> section should appear when at least one active, published item is assigned to the selected Most Sold Items category.</li><li>The <strong>Brands</strong> section should appear when at least one active, mobile-visible subcategory exists under the selected Brands parent category.</li><li>Tap a Most Sold item and confirm the product details screen opens.</li><li>Tap a Brand and confirm the app opens the product list for that brand.</li></ul></li></ol><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ol><li><p><strong>If the entire Most Sold Items or Brands section is missing from the home screen</strong></p><ul><li>The category name in <strong>Mobile E-Commerce Settings</strong> may not perfectly match the name in <strong>Item Category List</strong>.</li><li>Open <strong>Mobile E-Commerce Settings</strong>.</li><li>Check <strong>Most sold items category</strong> and <strong>Brand&#39;s parent category</strong>.</li><li>Compare each value with the exact category name in <strong>Item Category List</strong>.</li><li>Correct any typo, capitalization difference, or extra space.</li><li>Click <strong>Save</strong>, then fully close and reopen the mobile app.</li></ul></li><li><p><strong>If the Most Sold Items section is visible but empty</strong></p><ul><li>The selected Most Sold Items category exists, but no visible products are assigned to it.</li><li>Go to <strong>Item List</strong>.</li><li>Open the expected items.</li><li>Confirm each item is enabled, published, and assigned to the selected Most Sold Items category.</li><li>Confirm the items also meet the normal product catalog requirements for the mobile app.</li></ul></li><li><p><strong>If the Brands section is visible but empty</strong></p><ul><li>The Brands parent category exists, but it has no visible brand subcategories inside it.</li><li>Go to <strong>Item Category List</strong>.</li><li>Create or open each brand category.</li><li>Confirm <strong>Parent Item Category</strong> is set to the Brands parent category selected in <strong>Mobile E-Commerce Settings</strong>.</li><li>Confirm each brand category is active and has <strong>Show in Mobile Application</strong> checked.</li></ul></li><li><p><strong>If only some brands appear</strong></p><ul><li>The missing brand categories may not be under the correct Brands parent category.</li><li>Open each missing brand in <strong>Item Category List</strong>.</li><li>Confirm <strong>Parent Item Category</strong> is exactly the Brands parent category.</li><li>Confirm <strong>Show in Mobile Application</strong> is checked.</li><li>Save the category and retest the mobile app.</li></ul></li><li><p><strong>If a Most Sold product appears but cannot be used normally</strong></p><ul><li>The product may be assigned to the correct category, but its standard catalog setup is incomplete.</li><li>Open the item in <strong>Item List</strong>.</li><li>Confirm the item is enabled, published, has a valid image, has a mobile-visible selling UOM, has a valid price, and has available stock if the client is testing with a logged-in customer.</li></ul></li></ol>',7)])])}const m=t(r,[["render",a]]);export{h as __pageData,m as default};
